/// <summary>
/// areShipReceiveDatesChanged 
/// If header ShipReceiveDates are Changed do not show dialog to ask user and will update any TO lines 
/// </summary>
/// <param name = "_inventTransferTable">InventTransferTable</param>
/// <returns>boolean</returns>
protected boolean areShipReceiveDatesChanged(InventTransferTable _inventTransferTable)
{
    boolean ret = next areShipReceiveDatesChanged(_inventTransferTable);
    ;
    if(KJP_CM_Utils::checkCurExtIsKKC())
    {
        return false;
    }
    return ret;
}
